changeSet.sql:
CREATE OR REPLACE FUNCTION nexus.manifest_orphans(dim int) RETURNS TABLE( tenant_id text, doc_id text, "position" int, chash text, collection text ) LANGUAGE plpgsql SECURITY INVOKER AS $$ BEGIN -- Validate dim argument IF dim NOT IN (384, 768, 1024) THEN RAISE EXCEPTION 'manifest_orphans: unsupported dim %. Supported values: 384, 768, 1024', dim; END IF;
IF dim = 384 THEN RETURN QUERY SELECT c.tenant_id, c.doc_id, c.position, c.chash, c.collection FROM nexus.catalog_document_chunks c JOIN nexus.catalog_documents d ON d.tenant_id = c.tenant_id AND d.tumbler = c.doc_id AND d.deleted_at IS NULL LEFT JOIN nexus.chunks_384 k ON k.tenant_id = c.tenant_id AND k.collection = c.collection AND k.chash = c.chash WHERE c.collection IS NOT NULL AND split_part(c.collection, '__', 3) IN ('minilm-l6-v2-384') AND k.chash IS NULL;
ELSIF dim = 768 THEN RETURN QUERY SELECT c.tenant_id, c.doc_id, c.position, c.chash, c.collection FROM nexus.catalog_document_chunks c JOIN nexus.catalog_documents d ON d.tenant_id = c.tenant_id AND d.tumbler = c.doc_id AND d.deleted_at IS NULL LEFT JOIN nexus.chunks_768 k ON k.tenant_id = c.tenant_id AND k.collection = c.collection AND k.chash = c.chash WHERE c.collection IS NOT NULL AND split_part(c.collection, '__', 3) IN ('bge-base-en-v15-768') AND k.chash IS NULL;
ELSIF dim = 1024 THEN RETURN QUERY SELECT c.tenant_id, c.doc_id, c.position, c.chash, c.collection FROM nexus.catalog_document_chunks c JOIN nexus.catalog_documents d ON d.tenant_id = c.tenant_id AND d.tumbler = c.doc_id AND d.deleted_at IS NULL LEFT JOIN nexus.chunks_1024 k ON k.tenant_id = c.tenant_id AND k.collection = c.collection AND k.chash = c.chash WHERE c.collection IS NOT NULL AND split_part(c.collection, '__', 3) IN ('voyage-code-3', 'voyage-context-3', 'voyage-3') AND k.chash IS NULL; END IF; END; $$

GRANT EXECUTE ON FUNCTION nexus.manifest_orphans(int)   TO nexus_svc;
GRANT EXECUTE ON FUNCTION nexus.manifest_backfill()     TO nexus_svc;
GRANT EXECUTE ON FUNCTION nexus.document_text(text)     TO nexus_svc;

rollback.sql:
REVOKE EXECUTE ON FUNCTION nexus.document_text(text)     FROM nexus_svc;
REVOKE EXECUTE ON FUNCTION nexus.manifest_backfill()     FROM nexus_svc;
REVOKE EXECUTE ON FUNCTION nexus.manifest_orphans(int)   FROM nexus_svc;
